import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch26: CareerQuestion[] = [
  { id: "pta-b26-001", stem: "A patient with an incomplete SCI at C6 (ASIA D) has functional wrist extension but weak finger flexion. During ADL training, the PTA teaches the patient to use the tenodesis grasp for picking up a cup. The patient should:", options: ["Actively extend the wrist to passively flex the fingers around the cup, then flex the wrist to release", "Actively flex both the wrist and fingers simultaneously", "Use only the unaffected hand for all grasping tasks", "Wait for surgical hand reconstruction before attempting grasp activities"], correctIndex: 0, rationale: "Tenodesis grasp at C6 SCI: active wrist extension tightens the finger flexor tendons, causing passive finger flexion (grasp). Active wrist flexion loosens the tendons, causing finger opening (release). This passive mechanism allows functional grasp without intrinsic hand muscle activation. The PTA should NOT stretch the finger flexors as this would eliminate the tenodesis effect. Bilateral training and surgical referral are premature when tenodesis grasp is a functional option.", difficulty: 2, category: "Neurological Rehabilitation", topic: "SCI Tenodesis Grasp Training" },
  { id: "pta-b26-002", stem: "A 72-year-old patient with Parkinson's disease demonstrates micrographia, bradykinesia, and resting tremor. The PTA should incorporate which type of exercise to address bradykinesia?", options: ["Large-amplitude movement training (LSVT BIG) with exaggerated, high-effort movements in all planes", "Only fine motor exercises with small movements", "Rapid repetitive tapping exercises at maximum speed", "Complete avoidance of voluntary movement"], correctIndex: 0, rationale: "LSVT BIG (Lee Silverman Voice Treatment adapted for motor function) addresses bradykinesia through large-amplitude, high-effort movements. Parkinson's patients have an internal calibration deficit causing them to produce smaller movements than intended. LSVT BIG recalibrates movement amplitude through exaggerated practice. Small movements reinforce the existing deficit. Rapid repetitive tapping may worsen festination tendencies. Movement avoidance accelerates functional decline. The program involves intensive, high-repetition practice of large movements integrated into functional activities.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Parkinson's LSVT BIG" },
  { id: "pta-b26-003", stem: "A patient 3 weeks post-stroke demonstrates Brunnstrom Stage 3 upper extremity recovery (spastic synergy patterns present). During reaching activities, the patient demonstrates obligatory flexor synergy. The PTA should:", options: ["Use task-specific practice to encourage movement outside of synergy patterns, incorporating weight bearing and bilateral activities", "Reinforce the synergy pattern by only practicing flexion activities", "Immobilize the arm to prevent synergistic movement", "Wait until Stage 6 recovery before initiating any upper extremity treatment"], correctIndex: 0, rationale: "Brunnstrom Stage 3: strong spasticity with obligatory synergy patterns. Treatment encourages voluntary movement outside these patterns. Task-specific reaching activities challenge the patient to break out of the flexor synergy (shoulder flexion/abduction/ER, elbow extension). Weight bearing on the affected arm inhibits flexor spasticity through proprioceptive input. Bilateral activities use interlimb coupling. Reinforcing synergy patterns does not promote recovery. Immobilization promotes learned non-use. Waiting until Stage 6 misses the critical window for neuroplasticity. Each stage requires specific interventions to facilitate progression to the next.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Stroke Synergy Pattern Management" },
  { id: "pta-b26-004", stem: "A patient with a C7 complete SCI is training for independent transfers. The transfer technique that utilizes the patient's intact triceps for push-up transfers is called:", options: ["Depression transfer (push-up transfer) using triceps to extend the elbows and depress the shoulders to lift the buttocks and slide across the transfer surface", "Pivot transfer using standing and pivoting", "Mechanical lift transfer", "Dependent sliding board transfer with two assistants"], correctIndex: 0, rationale: "C7 SCI preserves triceps (elbow extension), allowing the patient to perform depression transfers (push-up style). The patient places hands on transfer surfaces, extends elbows (triceps), depresses shoulders (latissimus dorsi), lifts buttocks clear of the surface, and slides across. This is the gold standard for C7 SCI independence. Pivot transfers require standing ability (lower SCI). Mechanical lifts are for higher-level injuries or specific patient factors. Dependent transfers with two assistants are unnecessary with C7-level function. Sliding boards may be used initially for safety but are not needed once the technique is mastered.", difficulty: 2, category: "Neurological Rehabilitation", topic: "C7 SCI Transfer Technique" },
  { id: "pta-b26-005", stem: "A patient with multiple sclerosis experiences an exacerbation with increased spasticity, new weakness, and visual changes. The PTA should:", options: ["Reduce exercise intensity significantly, focus on gentle ROM and energy conservation, and communicate the exacerbation to the supervising PT immediately", "Increase exercise intensity to fight through the exacerbation", "Continue the current program without modification", "Discharge the patient from physical therapy permanently"], correctIndex: 0, rationale: "MS exacerbations (relapses) involve new or worsening neurological symptoms lasting >24 hours. During exacerbations: reduce exercise intensity to prevent worsening fatigue, focus on gentle ROM to prevent contractures, use energy conservation strategies, and communicate findings to the PT immediately (may require medical management with corticosteroids). Increasing intensity during a relapse worsens fatigue and may prolong the exacerbation. Continuing without modification ignores the changed status. Discharge is premature; patients need rehabilitation support during and after exacerbations. The program should be modified based on current functional status and gradually progressed as the exacerbation resolves.", difficulty: 2, category: "Neurological Rehabilitation", topic: "MS Exacerbation Exercise Modification" },
  { id: "pta-b26-006", stem: "A patient with left hemiplegia after a right MCA stroke demonstrates pusher syndrome (contraversive pushing). The patient actively pushes toward the hemiplegic (left) side and resists correction to midline. The PTA should:", options: ["Use visual vertical references (mirrors, vertical lines), guide the patient to actively shift weight toward the stronger (right) side, and avoid forceful passive correction", "Push the patient forcefully to the right side", "Allow the patient to continue falling to the left without intervention", "Only treat the patient in supine to avoid the pushing behavior"], correctIndex: 0, rationale: "Pusher syndrome involves a distorted perception of postural vertical. The patient perceives upright as tilted and actively pushes toward the hemiplegic side. Treatment: visual vertical references (mirrors, vertical lines on walls) provide external vertical cues, active weight-shifting toward the non-hemiplegic side retrains postural perception, and verbal cueing promotes self-correction. Forceful passive correction increases the pushing response (the patient pushes harder against correction). Allowing falls is unsafe. Supine-only treatment avoids rather than addresses the dysfunction. The condition resolves with consistent, patient-guided retraining of vertical perception.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Stroke Pusher Syndrome Treatment" },
  { id: "pta-b26-007", stem: "A PTA is treating a 6-year-old child with Duchenne muscular dystrophy (DMD). The child demonstrates Gowers sign when rising from the floor. This sign indicates:", options: ["Proximal muscle weakness requiring the child to 'walk up' their legs with their hands to stand, due to weak hip extensors and knee extensors", "Strong quadriceps muscles", "Normal development for a 6-year-old", "A cognitive deficit affecting motor planning"], correctIndex: 0, rationale: "Gowers sign is pathognomonic for DMD: the child rolls prone, pushes up to hands and knees, then places hands on thighs and 'walks up' the legs to achieve standing. This compensates for severe proximal weakness (hip extensors, knee extensors, trunk muscles). It is NOT normal development; most children stand from the floor without this compensation by age 3-4. The sign does not indicate cognitive deficit. DMD is a progressive X-linked recessive disorder with progressive proximal-to-distal weakness. Treatment focuses on maintaining mobility, preventing contractures, and maximizing function for as long as possible. Eccentric and high-resistance exercise should be avoided as it may accelerate muscle damage.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "DMD Gowers Sign" },
  { id: "pta-b26-008", stem: "A patient with a traumatic brain injury at Rancho Los Amigos Level IV (Confused-Agitated) is in the therapy gym. The patient is yelling, attempting to pull out lines, and is disoriented. The PTA should:", options: ["Provide a calm, quiet, low-stimulation environment, use short simple commands, ensure patient safety, and avoid restraints when possible by redirecting behavior", "Restrain the patient in a wheelchair and proceed with complex exercises", "Argue with the patient to correct their confusion", "Leave the patient unsupervised in the gym"], correctIndex: 0, rationale: "Rancho Level IV (Confused-Agitated): the patient is in a heightened state of confusion with bizarre/non-purposeful behavior, severely limited attention, and agitation. Treatment approach: minimize environmental stimulation (quiet room, reduced visitors, dim lighting), use short simple commands (one-step directions), prioritize safety (fall prevention, line protection), avoid restraints when possible (increase agitation), redirect rather than confront, and keep sessions brief. Restraints and complex exercises worsen agitation. Arguing increases confusion and agitation. Unsupervised patients at Level IV are a safety risk. The goal is patient safety while the brain recovers from the acute confusional state.", difficulty: 2, category: "Neurological Rehabilitation", topic: "TBI Rancho Level IV Management" },
  { id: "pta-b26-009", stem: "A patient with ALS (amyotrophic lateral sclerosis) presents with progressive weakness, currently demonstrating 3/5 strength in the lower extremities. The PTA should design an exercise program that:", options: ["Includes submaximal aerobic exercise and low-to-moderate resistance exercise, avoiding fatigue and overwork weakness, with focus on maintaining current function", "Pushes the patient to maximum effort to prevent further weakness", "Includes only passive ROM with no active exercise", "Avoids all exercise as it may accelerate disease progression"], correctIndex: 0, rationale: "ALS exercise prescription must balance maintaining function with avoiding overwork weakness (exercise-induced damage to already compromised motor neurons). Submaximal aerobic and low-to-moderate resistance exercise maintains cardiovascular fitness and current strength without exceeding motor neuron capacity. Maximum effort exercise risks overwork weakness and accelerated motor neuron loss. Passive ROM alone does not maintain the muscle function that is still present. Evidence supports that appropriate exercise does not accelerate ALS progression and may improve quality of life and function temporarily. As the disease progresses, the program must be continuously adjusted to declining function.", difficulty: 3, category: "Neurological Rehabilitation", topic: "ALS Exercise Prescription" },
  { id: "pta-b26-010", stem: "During constraint-induced movement therapy (CIMT) for a patient with chronic stroke, the unaffected upper extremity is restrained for approximately what percentage of waking hours?", options: ["90% of waking hours (typically using a padded mitt), with intensive task-specific practice with the affected arm for 6+ hours daily over 2 weeks", "10% of waking hours", "Only during 30-minute therapy sessions twice a week", "24 hours per day including during sleep"], correctIndex: 0, rationale: "Traditional CIMT protocol: restraint of the less-affected arm for 90% of waking hours (padded mitt prevents use but allows emergency removal), intensive shaping and task practice with the affected arm for 6+ hours per day, over a concentrated 2-week period. The high dose of forced-use practice drives cortical reorganization through neuroplasticity. Modified CIMT (mCIMT) reduces intensity to 3 hours daily with 5 hours restraint for patients who cannot tolerate the full protocol. 10% restraint or brief twice-weekly sessions provide insufficient stimulus. Sleep restraint is unnecessary and unsafe. Inclusion criteria typically require 20° wrist extension and 10° finger extension on the affected side.", difficulty: 2, category: "Neurological Rehabilitation", topic: "CIMT Protocol Parameters" },
  { id: "pta-b26-011", stem: "A patient with peripheral vestibular hypofunction reports room-spinning vertigo when rolling in bed to the right side. The Dix-Hallpike test is positive on the right. This is consistent with:", options: ["Benign paroxysmal positional vertigo (BPPV) of the right posterior semicircular canal, treatable with the Epley canalith repositioning maneuver", "Central vestibular dysfunction requiring immediate MRI", "Meniere's disease requiring surgical intervention", "Normal vestibular function"], correctIndex: 0, rationale: "Positive Dix-Hallpike test (upbeating, torsional nystagmus with latency, limited duration, and fatigability on the right) indicates BPPV of the right posterior semicircular canal. Otoconia (calcium carbonate crystals) displaced from the utricle into the posterior canal cause vertigo with position changes. The Epley maneuver repositions the otoconia back to the utricle through a series of head positions utilizing gravity. Central vestibular dysfunction produces different nystagmus patterns (pure vertical, direction-changing, no latency). Meniere's disease presents with episodic vertigo, hearing loss, tinnitus, and aural fullness. BPPV is the most common cause of positional vertigo and responds well to repositioning maneuvers.", difficulty: 2, category: "Neurological Rehabilitation", topic: "BPPV Diagnosis and Treatment" },
  { id: "pta-b26-012", stem: "A PTA is treating a patient with myasthenia gravis. The patient's weakness characteristically:", options: ["Worsens with repeated activity and improves with rest, due to antibody-mediated destruction of acetylcholine receptors at the neuromuscular junction", "Is constant throughout the day regardless of activity", "Improves with exercise and worsens with rest", "Only affects the lower extremities"], correctIndex: 0, rationale: "Myasthenia gravis is an autoimmune disorder where antibodies destroy acetylcholine receptors at the neuromuscular junction. Hallmark feature: fatigable weakness that worsens with repeated activity (acetylcholine depletion at damaged receptors) and improves with rest (acetylcholine replenishment). Common presentation: ptosis, diplopia, dysphagia, and proximal limb weakness that worsen throughout the day. Exercise must be carefully dosed to avoid myasthenic crisis (severe respiratory weakness). MG affects all voluntary muscles, not just lower extremities. Treatment includes anticholinesterase medications (pyridostigmine), immunosuppressants, and carefully graded exercise.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Myasthenia Gravis Exercise" },
  { id: "pta-b26-013", stem: "A patient with a T4 complete SCI is performing wheelchair push-ups for pressure relief. The PTA should ensure the patient performs these:", options: ["Every 15-30 minutes, lifting the buttocks off the seat for at least 15-30 seconds to allow tissue reperfusion and prevent pressure injury", "Once daily for 5 seconds", "Only when the patient feels discomfort", "Every 4 hours for 2 seconds"], correctIndex: 0, rationale: "SCI patients lack sensation below the injury level and cannot perceive pressure-related discomfort. Wheelchair push-ups (pressure relief lifts) must be performed every 15-30 minutes for a minimum of 15-30 seconds to allow adequate tissue reperfusion. This prevents ischemic tissue damage that leads to pressure injuries (the #1 secondary complication in SCI). Once daily is grossly insufficient. Waiting for discomfort is impossible in a patient without sensation. Every 4 hours for 2 seconds provides neither adequate frequency nor duration. Alternative pressure relief methods include forward lean (if trunk control allows) and side-to-side weight shifts. Pressure-redistributing wheelchair cushions supplement but do not replace active pressure relief.", difficulty: 2, category: "Neurological Rehabilitation", topic: "SCI Pressure Relief Schedule" },
  { id: "pta-b26-014", stem: "A patient with Huntington's disease demonstrates chorea (involuntary, irregular movements) and progressive cognitive decline. The PTA's exercise program should:", options: ["Focus on fall prevention, gait safety with assistive devices, functional strengthening, and environmental modifications for safety, adapting as the disease progresses", "Include rapid agility drills on unstable surfaces", "Remain static throughout the disease course without modification", "Focus exclusively on cognitive exercises with no physical activity"], correctIndex: 0, rationale: "Huntington's disease is progressive with involuntary movements (chorea), declining motor control, and cognitive deterioration. Physical therapy focuses on: fall prevention (highest priority due to balance impairment from chorea), gait safety training with assistive devices as needed, functional strengthening to maintain independence, and environmental modifications (remove tripping hazards, padded furniture edges). Programs must be continuously adapted as the disease progresses. Rapid agility drills on unstable surfaces create unacceptable fall risk. Static programs fail to address progressive decline. Physical activity is essential; cognitive-only approaches miss the significant motor component.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Huntington's Disease Rehabilitation" },
  { id: "pta-b26-015", stem: "A 10-month-old infant is referred for physical therapy with a diagnosis of developmental delay. The infant cannot sit independently and does not bear weight on the lower extremities when held in standing. These milestones are typically achieved by:", options: ["6-7 months (independent sitting) and 5-6 months (weight bearing in supported standing), indicating approximately 4-5 month delay", "12 months, so the infant is on track", "24 months, so the delay is minimal", "These milestones are not expected until age 3"], correctIndex: 0, rationale: "Gross motor milestone timeline: independent sitting typically achieved by 6-7 months, weight bearing in supported standing by 5-6 months. A 10-month-old who cannot sit independently or bear weight in supported standing is approximately 4-5 months delayed in gross motor development. This warrants early intervention physical therapy to address the underlying motor deficits (hypotonia, weakness, motor planning). Independent walking is expected by 12 months (not sitting). Most gross motor milestones except complex skills (skipping, hopping on one foot) are achieved before 24 months. Delayed milestones may indicate cerebral palsy, genetic syndromes, or other neurodevelopmental conditions requiring comprehensive evaluation.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Developmental Delay Assessment" },
  { id: "pta-b26-016", stem: "A PTA is performing postural drainage for a patient with cystic fibrosis who has secretions in the left upper lobe. The appropriate position for drainage of the left upper lobe is:", options: ["Semi-reclined sitting at approximately 45°, rotated slightly to the right to allow gravity to drain the left upper lobe toward the main bronchus", "Trendelenburg (head down) position", "Right sidelying flat in bed", "Prone with head down and pillows under the hips"], correctIndex: 0, rationale: "The upper lobes are best drained in upright or semi-reclined positions because they sit superiorly in the thorax. For the left upper lobe: semi-reclined at 45° with slight right rotation positions the left upper lobe above the carina, allowing gravity-assisted drainage toward the central airways. Trendelenburg is used for lower lobes (positions lower lobes above the carina). Right sidelying flat does not optimize upper lobe drainage. Prone head-down positions are for posterior basal segments of lower lobes. Each lung segment has a specific drainage position based on its anatomical orientation relative to the bronchial tree. Postural drainage is combined with percussion, vibration, and huffing/coughing.", difficulty: 3, category: "Cardiopulmonary Physical Therapy", topic: "CF Upper Lobe Drainage" },
  { id: "pta-b26-017", stem: "A PTA is treating a patient with complex regional pain syndrome (CRPS) of the hand. Mirror therapy involves:", options: ["Placing a mirror between the hands so the patient sees the reflection of the unaffected hand moving, creating a visual illusion that the affected hand is moving normally and pain-free", "Looking in a bathroom mirror while exercising the affected hand", "Using a mirror to observe posture during standing", "Reflecting light onto the affected hand for therapeutic effect"], correctIndex: 0, rationale: "Mirror therapy for CRPS uses a mirror between the limbs to create a visual illusion: the patient sees the unaffected hand's reflection superimposed where the affected hand would be. When the unaffected hand moves, the visual feedback suggests the affected hand is moving normally and without pain. This visual-motor illusion helps reorganize the cortical representation of the affected limb, which becomes distorted in CRPS. The mechanism involves activation of mirror neurons and normalization of the body schema. Mirror therapy is supported by evidence for CRPS, phantom limb pain, and stroke rehabilitation. It is a key component of graded motor imagery programs.", difficulty: 2, category: "Pain Management", topic: "Mirror Therapy CRPS" },
  { id: "pta-b26-018", stem: "A PTA is treating a patient with a T10 paraplegia who wants to ambulate using bilateral KAFOs and forearm crutches. The most energy-efficient gait pattern for this patient would be:", options: ["Swing-through gait pattern, where both crutches advance first, then both legs swing past the crutches, maximizing speed and energy efficiency", "Four-point alternating gait pattern", "Independent walking without assistive devices", "Two-point alternating gait pattern"], correctIndex: 0, rationale: "With T10 paraplegia and bilateral KAFOs, the swing-through gait pattern is most energy-efficient for community distances: both crutches are placed forward, then both legs swing past the crutches (using trunk/upper body momentum). This pattern covers the most distance per cycle. Four-point and two-point alternating patterns require more steps and are slower and more energy-consuming with KAFOs. Independent walking without devices is not possible with T10 complete paraplegia. However, even swing-through gait with KAFOs requires 4-6x more energy than normal walking, which is why most T10 patients use wheelchair for primary mobility and KAFOs for exercise ambulation.", difficulty: 3, category: "Gait Training & Assistive Devices", topic: "SCI KAFO Gait Pattern" },
  { id: "pta-b26-019", stem: "A patient 6 months post-stroke has persistent upper extremity flaccidity (Brunnstrom Stage 1). The PTA should focus intervention on:", options: ["Maintaining passive ROM, protecting the flaccid shoulder from subluxation, and attempting sensory stimulation and facilitation techniques to elicit any voluntary movement", "Aggressive resistance training with heavy weights", "Ignoring the affected arm entirely", "Applying a permanent cast to the affected arm"], correctIndex: 0, rationale: "Brunnstrom Stage 1 (flaccidity with no voluntary movement): PROM maintains joint integrity and prevents contractures, shoulder subluxation management (lap tray, arm trough, Bobath sling in standing) prevents stretching of the joint capsule and brachial plexus, and sensory stimulation (tapping, quick stretch, vibration, weight bearing) and facilitation techniques attempt to activate motor pathways. Resistance training is impossible without voluntary movement. Ignoring the arm promotes learned non-use and allows contractures. Casting immobilizes and contributes to further disuse. Even at 6 months, neuroplasticity allows potential for motor recovery with appropriate stimulation.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Stroke Stage 1 Flaccidity Management" },
  { id: "pta-b26-020", stem: "A PTA is treating a child with spina bifida at the L3-L4 level. The expected functional mobility for this level includes:", options: ["Community ambulation with bilateral AFOs and forearm crutches, with a wheelchair available for long distances and energy conservation", "Independent ambulation without any assistive devices", "Wheelchair-only mobility with no standing ability", "Full athletic participation without any adaptive equipment"], correctIndex: 0, rationale: "L3-L4 spina bifida preserves quadriceps function (hip flexors, knee extensors, some hip adductors) but loses ankle dorsiflexors, plantarflexors, and hip abductors/extensors. Functional mobility: community ambulation with bilateral AFOs (controlling the ankle) and forearm crutches (compensating for hip weakness), with wheelchair for long distances due to increased energy expenditure. Independent ambulation without devices is not possible due to absent ankle and hip musculature. Wheelchair-only mobility underestimates the functional potential. Athletic participation is possible with adaptive equipment (wheelchair sports, swimming). The PTA should focus on strengthening available muscles, orthotic management, and gait training.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Spina Bifida L3-L4 Function" },
  { id: "pta-b26-021", stem: "A PTA is treating a patient who demonstrates ataxic gait following a cerebellar stroke. Characteristics of cerebellar ataxia include:", options: ["Wide-based gait with irregular step length, veering/staggering, dysmetria, and intention tremor that worsens with goal-directed movement", "Narrow-based gait with regular cadence", "Festinating gait with small shuffling steps", "Circumduction of one lower extremity"], correctIndex: 0, rationale: "Cerebellar ataxia produces: wide-based gait (compensating for balance dysfunction), irregular step length and timing (loss of motor coordination), veering/staggering (loss of trunk coordination), dysmetria (over/undershooting targets), and intention tremor (tremor that worsens as the limb approaches a target, unlike Parkinson's resting tremor). Narrow-based regular gait is normal. Festinating gait is Parkinson's disease. Circumduction is typical of spastic hemiplegia (stroke affecting the motor cortex/internal capsule). Treatment for cerebellar ataxia focuses on: weighted vests/anklets for sensory feedback, wide base of support training, coordination exercises (finger-to-nose, heel-to-shin), and gait training with assistive devices.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cerebellar Ataxia Gait" },
  { id: "pta-b26-022", stem: "A PTA is performing active-assisted ROM for a patient with left shoulder subluxation following a stroke. To protect the glenohumeral joint during AAROM, the PTA should:", options: ["Support the humeral head in the glenoid fossa by applying gentle upward pressure on the humerus while performing the range of motion exercises", "Allow the arm to hang freely without support during all exercises", "Forcefully pull the arm into overhead flexion", "Only perform exercises with the patient standing"], correctIndex: 0, rationale: "Post-stroke shoulder subluxation results from loss of rotator cuff muscle tone allowing the humeral head to slide inferiorly from the glenoid fossa. During AAROM, the PTA must manually support the humeral head in the glenoid by applying gentle upward (superior) pressure on the proximal humerus. This prevents further stretching of the joint capsule and brachial plexus during exercise. Allowing the arm to hang freely increases subluxation. Forceful overhead flexion without support risks impingement and further subluxation. Standing position makes it harder to provide manual support; supine or seated positions are preferred. Proper handling technique is essential to prevent shoulder-hand syndrome.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Stroke Subluxation AAROM Protection" },
  { id: "pta-b26-023", stem: "A patient with a recent diagnosis of Bell's palsy (idiopathic facial nerve paralysis) presents with inability to close the right eye, drooping of the right mouth corner, and difficulty drinking. The PTA should:", options: ["Teach facial exercises (eye closure, lip pursing, cheek puffing), provide neuromuscular re-education with mirror feedback, and ensure eye protection (eye drops, taping at night)", "Apply aggressive electrical stimulation to the facial muscles at maximum intensity", "Inform the patient that no treatment is beneficial for Bell's palsy", "Only provide cervical spine treatment"], correctIndex: 0, rationale: "Bell's palsy (CN VII palsy) treatment includes facial exercises targeting specific muscle groups (frontalis for eyebrow elevation, orbicularis oculi for eye closure, orbicularis oris for lip function, buccinator for cheek function), mirror biofeedback for neuromuscular re-education (patient watches their face while performing exercises), and eye protection (artificial tears, nighttime taping or moisture chamber to prevent corneal drying/ulceration). Aggressive electrical stimulation may produce mass synkinesis (abnormal co-contraction of facial muscles). Physical therapy is beneficial; 85% of patients recover fully within 3-6 months. Cervical treatment does not address the facial nerve dysfunction.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Bell's Palsy Rehabilitation" },
  { id: "pta-b26-024", stem: "A PTA is providing education to a patient with newly diagnosed diabetes about foot care. Which instruction is MOST important for preventing diabetic foot ulcers?", options: ["Inspect feet daily for redness, blisters, cuts, or swelling; wear properly fitting shoes; never walk barefoot; and report any changes to the healthcare provider immediately", "Only check feet once a year at the doctor's office", "Soak feet in hot water daily for 30 minutes", "Cut toenails as short as possible with regular scissors"], correctIndex: 0, rationale: "Diabetic foot ulcer prevention centers on daily inspection because peripheral neuropathy eliminates protective pain sensation, meaning tissue damage goes unnoticed. Key instructions: daily visual inspection (use a mirror for soles), proper footwear (seamless interior, adequate depth, no pressure points), never walk barefoot (risk of undetected injury), moisturize skin (prevent cracks but not between toes), cut nails straight across (prevent ingrown nails), and immediate reporting of changes. Annual-only checks allow problems to progress undetected. Hot water soaks risk burns (impaired temperature sensation). Cutting nails too short risks injury. Diabetic foot ulcers are the leading cause of non-traumatic lower extremity amputation.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Diabetic Foot Care Education" },
  { id: "pta-b26-025", stem: "A PTA notices that a patient on a beta-blocker (metoprolol) has a blunted heart rate response during exercise. The heart rate does not exceed 95 bpm despite vigorous exercise. The PTA should use which alternative method to gauge exercise intensity?", options: ["Rate of Perceived Exertion (RPE) scale (Borg 6-20), targeting 12-14 for moderate intensity exercise", "Only heart rate-based monitoring, ignoring the medication effect", "Maximum effort testing to determine true peak heart rate", "No monitoring of exercise intensity is needed"], correctIndex: 0, rationale: "Beta-blockers (metoprolol, atenolol, propranolol) block beta-adrenergic receptors, attenuating the heart rate and blood pressure response to exercise. Heart rate alone is unreliable for exercise intensity monitoring. Rate of Perceived Exertion (RPE) on the Borg 6-20 scale provides a subjective but validated alternative: 12-14 corresponds to moderate intensity regardless of heart rate. The Talk Test is another alternative (can talk but not sing = moderate intensity). Relying only on heart rate underestimates exercise intensity in beta-blocked patients. Maximum effort testing may be unsafe. All patients on heart rate-altering medications require alternative intensity monitoring methods.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Beta-Blocker RPE Monitoring" },
  { id: "pta-b26-026", stem: "A PTA is conducting a home safety assessment for a geriatric patient being discharged after a hip fracture. Which environmental modification has the STRONGEST evidence for fall prevention?", options: ["Removal of throw rugs, installation of grab bars in the bathroom (near toilet and in shower), adequate lighting especially in hallways and stairways, and non-slip mats in the tub/shower", "Only adding a handrail to one side of the stairs", "Recommending the patient avoid leaving their bedroom", "Installing only motion-sensor outdoor lighting"], correctIndex: 0, rationale: "Evidence-based home modification for fall prevention: throw rug removal eliminates trip hazards (leading cause of home falls), bathroom grab bars reduce fall risk during transfers and bathing (bathroom is the most common location for falls), adequate lighting improves visual perception of hazards, and non-slip mats prevent slipping on wet surfaces. A single handrail is insufficient compared to a comprehensive assessment. Confining the patient to the bedroom reduces quality of life and promotes deconditioning. Outdoor lighting alone does not address the primary fall location (inside the home). The home safety assessment should be systematic, covering all rooms, transitions between surfaces, and outdoor access areas.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Home Safety Fall Prevention" },
  { id: "pta-b26-027", stem: "A PTA is treating a patient with a diagnosed deep vein thrombosis (DVT) in the left calf. Until the patient has been adequately anticoagulated, the PTA should:", options: ["Avoid vigorous lower extremity exercise, deep tissue massage of the affected leg, and dependent positioning until cleared by the physician", "Perform aggressive calf massage to break up the clot", "Have the patient perform maximum-effort calf raises", "Apply compression stockings without physician authorization"], correctIndex: 0, rationale: "Active DVT is a medical emergency due to the risk of pulmonary embolism. Until the patient is therapeutically anticoagulated (confirmed by the physician): avoid vigorous LE exercise (may dislodge the clot), absolutely no massage of the affected leg (can dislodge the clot and cause PE), avoid dependent positioning (promotes venous stasis), and no compression garments until cleared by physician (may dislodge the clot). Once anticoagulated, gentle ankle pumps and early mobilization are typically permitted. Calf massage with active DVT is contraindicated. Maximum-effort calf raises could dislodge the clot. Compression stockings require physician authorization with active DVT. The PTA should recognize Homans' sign (calf pain with passive dorsiflexion) as a potential DVT indicator, though it has low sensitivity.", difficulty: 2, category: "Patient Safety & Body Mechanics", topic: "DVT Exercise Precautions" },
  { id: "pta-b26-028", stem: "A PTA is teaching a patient with a new transtibial (below-knee) amputation how to properly wrap the residual limb with an elastic bandage. The wrapping technique should:", options: ["Use figure-8 turns with diagonal wrapping from distal to proximal, applying more pressure distally and less proximally, to shape the limb into a conical form for prosthetic fitting", "Wrap in circular turns only with equal pressure throughout", "Wrap from proximal to distal with maximum tightness at the top", "Apply the bandage loosely without any specific pattern"], correctIndex: 0, rationale: "Residual limb wrapping serves to: control edema, shape the limb into a conical form for prosthetic socket fitting, and desensitize the limb. Figure-8 diagonal wrapping prevents tourniquet effect (circular wraps can constrict). Distal-to-proximal wrapping with greater distal pressure and decreasing proximal pressure promotes venous return and prevents distal edema. Circular-only turns create a tourniquet effect at each turn. Proximal-to-distal wrapping with tight proximal pressure traps fluid distally. Loose wrapping without pattern does not achieve shaping or edema control. The bandage should be rewrapped every 4-6 hours or when loose. Once the limb stabilizes, a shrinker sock may replace elastic bandaging.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "Residual Limb Wrapping Technique" },
  { id: "pta-b26-029", stem: "A PTA is assessing a patient's respiratory function using the incentive spirometer. The patient achieves 1200 mL on the device. To determine if this is adequate, the PTA should know that predicted inspiratory capacity is based on:", options: ["The patient's age, gender, and height, with expected values compared to population norms; 1200 mL may be low for a tall young male but adequate for a small elderly female", "A universal standard of 1000 mL for all patients regardless of demographics", "Only the patient's weight", "Only the patient's diagnosis"], correctIndex: 0, rationale: "Inspiratory capacity (IC) is predicted based on patient demographics: age (decreases with age), gender (males have larger lung volumes), and height (taller individuals have larger thoracic cavity). Expected IC values vary significantly: a 25-year-old tall male may have a predicted IC of 3000+ mL, making 1200 mL a significant deficit. A 75-year-old small female may have a predicted IC of 1500 mL, making 1200 mL approximately 80% predicted. There is no universal standard as lung volumes are highly individual. Weight alone does not predict IC (though obesity may restrict volumes). Diagnosis affects current function but not the predicted baseline. The PTA should compare the achieved value to the predicted value to assess adequacy.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Inspiratory Capacity Assessment" },
  { id: "pta-b26-030", stem: "A PTA is treating a patient with shoulder impingement who also has a thoracic kyphosis. The relationship between thoracic posture and shoulder impingement is:", options: ["Increased thoracic kyphosis reduces the available subacromial space by tilting the scapula anteriorly, contributing to mechanical impingement of the rotator cuff tendons", "Thoracic posture has no relationship to shoulder mechanics", "Increased kyphosis increases subacromial space", "Only cervical posture affects shoulder mechanics"], correctIndex: 0, rationale: "Thoracic kyphosis directly affects shoulder mechanics through the kinetic chain. Increased kyphosis: tilts the scapula anteriorly (increases anterior tilt, decreases upward rotation), reduces the subacromial space, and increases impingement of the supraspinatus tendon and subacromial bursa during overhead activities. Treatment must address thoracic extension mobility, not just local shoulder interventions. Thoracic extension exercises and mobilization can improve shoulder ROM and reduce impingement symptoms. Both cervical AND thoracic posture affect shoulder mechanics. The PTA should assess the entire kinetic chain (thoracic spine, scapula, glenohumeral joint) when treating shoulder impingement.", difficulty: 3, category: "Biomechanics & Kinesiology", topic: "Thoracic Kyphosis Shoulder Impingement" },
  { id: "pta-b26-031", stem: "A patient who is 2 days post-cesarean section is referred for physical therapy. The PTA should focus on:", options: ["Gentle abdominal bracing (transversus abdominis activation), breathing exercises, bed mobility training, progressive ambulation, and incision site protection during activity", "Aggressive abdominal crunches and sit-ups to restore core strength", "Complete bed rest for 2 weeks", "Heavy resistance training for the lower extremities"], correctIndex: 0, rationale: "Post-cesarean rehabilitation at 2 days focuses on safe early mobilization: gentle transversus abdominis activation (drawing-in maneuver, not crunching) supports the surgical site, diaphragmatic breathing maintains pulmonary function (reduces atelectasis risk), bed mobility training with log-roll technique protects the incision, and progressive ambulation prevents DVT and promotes recovery. Aggressive abdominal exercises risk incision dehiscence and are contraindicated in the early postoperative period. Complete bed rest increases DVT and pulmonary complication risk. Heavy LE resistance training creates excessive intra-abdominal pressure. Pillow splinting over the incision during coughing provides pain relief and incision protection.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Post-Cesarean Early Mobilization" },
  { id: "pta-b26-032", stem: "A PTA is using biofeedback with surface EMG to train a patient in isolated contraction of the vastus medialis oblique (VMO) for patellofemoral pain syndrome. The biofeedback helps by:", options: ["Providing real-time visual or auditory feedback of VMO muscle activation, allowing the patient to learn to selectively recruit the VMO relative to the vastus lateralis", "Directly strengthening the muscle through electrical current", "Replacing all other exercise interventions", "Measuring joint range of motion"], correctIndex: 0, rationale: "Surface EMG biofeedback provides real-time feedback of muscle electrical activity, allowing patients to visualize their VMO activation patterns. This facilitates motor learning by: showing the patient when the VMO is active vs. inactive, comparing VMO activation to VL activation (addressing imbalanced recruitment), and reinforcing correct activation patterns through auditory/visual cues. Biofeedback does not directly strengthen muscles (no external electrical current). It supplements but does not replace therapeutic exercise. It measures muscle electrical activity, not joint ROM. Biofeedback is a motor learning tool that enhances volitional muscle control, particularly useful when patients have difficulty activating specific muscles.", difficulty: 2, category: "Therapeutic Exercise", topic: "EMG Biofeedback VMO Training" },
  { id: "pta-b26-033", stem: "A PTA is providing aquatic therapy for a patient with rheumatoid arthritis. The water temperature should be maintained at:", options: ["92-96°F (33-36°C) for therapeutic warmth that reduces pain and stiffness without exacerbating inflammation in a controlled flare", "50-60°F (10-16°C) cold plunge temperature", "104-110°F (40-43°C) hot tub temperature", "Room temperature 68°F (20°C)"], correctIndex: 0, rationale: "Aquatic therapy for RA uses water at 92-96°F (33-36°C), which provides: therapeutic warmth (reduces pain, decreases joint stiffness, relaxes muscles), buoyancy (reduces joint loading by 50-90% depending on immersion depth), and hydrostatic pressure (reduces edema). Cold water (50-60°F) would increase stiffness and pain in RA. Hot tub temperatures (>104°F) may exacerbate inflammation and are contraindicated in acute flares and for patients with cardiovascular conditions. Room temperature water provides insufficient thermal benefit and may be uncomfortable. During acute RA flares, cooler therapeutic pool temperatures (88-92°F) may be preferable to avoid exacerbating inflammation.", difficulty: 2, category: "Therapeutic Modalities", topic: "Aquatic Therapy RA Temperature" },
  { id: "pta-b26-034", stem: "A PTA receives a referral for a new patient. Upon reviewing the plan of care, the PTA determines that the PT has delegated an intervention that the PTA does not feel competent to perform (spinal mobilization technique). The PTA should:", options: ["Communicate directly with the supervising PT about the competency concern, request additional training or modification of the treatment plan, and document the communication", "Attempt the technique despite feeling incompetent", "Refuse to see the patient entirely without communicating with the PT", "Perform a different intervention without discussing it with the PT"], correctIndex: 0, rationale: "Professional ethics and patient safety require the PTA to communicate competency concerns with the supervising PT. The APTA Code of Ethics and state practice acts require practitioners to practice within their competence. The appropriate action: directly discuss the concern with the PT, request training in the technique or ask for plan of care modification to include interventions within the PTA's competency, and document the communication. Attempting techniques beyond competence risks patient harm. Refusing to see the patient without communication abandons care and violates professional responsibility. Performing unauthorized alternative interventions deviates from the plan of care without PT approval.", difficulty: 1, category: "Ethics & Professional Practice", topic: "PTA Competency Communication" },
  { id: "pta-b26-035", stem: "A PTA is treating a patient who is receiving chemotherapy and has a platelet count of 25,000/mm³ (normal: 150,000-400,000/mm³). The exercise program should be modified to:", options: ["Avoid all activities with fall risk or contact, use only gentle active ROM and low-intensity exercise, avoid resistive exercise, and monitor for signs of bleeding", "Perform high-intensity plyometric training", "Continue all exercises without modification", "Apply deep tissue massage to all major muscle groups"], correctIndex: 0, rationale: "Thrombocytopenia (platelet count <50,000/mm³) significantly increases bleeding risk. At 25,000/mm³: avoid fall-risk activities (no balance challenges on unstable surfaces), avoid contact activities, use only gentle AROM and low-intensity exercise (avoid Valsalva and heavy resistance which can raise blood pressure and cause hemorrhage), and monitor for petechiae, bruising, nosebleeds, and hematuria. At <20,000/mm³, only bed exercises may be appropriate. At <10,000/mm³, active exercise is generally contraindicated. Plyometrics, unmodified exercise, and deep tissue massage all risk hemorrhage in severely thrombocytopenic patients. The PTA must review lab values before each treatment session during chemotherapy.", difficulty: 3, category: "Clinical Prioritization & Workflow", topic: "Thrombocytopenia Exercise Modification" },
  { id: "pta-b26-036", stem: "A PTA is treating a patient with chronic heart failure (NYHA Class III). The patient can perform activities of daily living but becomes symptomatic with less than ordinary activity. The exercise prescription should:", options: ["Include low-intensity interval training with frequent rest breaks, monitoring dyspnea, fatigue, and weight gain daily, with exercise intensity guided by symptoms and RPE", "Consist of continuous high-intensity aerobic exercise for 60 minutes", "Be limited to complete bed rest", "Include maximum-effort resistance training"], correctIndex: 0, rationale: "NYHA Class III heart failure: comfortable at rest but symptomatic (dyspnea, fatigue) with less than ordinary physical activity. Exercise prescription: low-intensity interval training (short exercise bouts with rest periods), symptom-guided intensity using RPE (Borg 11-13, light to somewhat hard), daily weight monitoring (>2 lb gain in 24 hours may indicate fluid retention/decompensation), and monitoring for exercise intolerance signs (excessive dyspnea, peripheral edema increase, jugular vein distension). Continuous high-intensity exercise exceeds cardiac reserve capacity. Bed rest leads to further deconditioning. Maximum resistance training causes excessive blood pressure elevation. Exercise has been shown to improve functional capacity even in Class III HF when appropriately prescribed.", difficulty: 3, category: "Cardiopulmonary Physical Therapy", topic: "Heart Failure NYHA III Exercise" },
  { id: "pta-b26-037", stem: "A PTA observes a patient with a transtibial prosthesis who demonstrates excessive knee flexion at initial contact during gait. The MOST likely cause is:", options: ["The prosthetic foot is set in excessive dorsiflexion, or the socket is flexed too far forward, causing the ground reaction force to pass behind the knee joint", "The prosthetic foot is set in excessive plantarflexion", "The patient's hip extensors are too strong", "The prosthetic limb is too long"], correctIndex: 0, rationale: "Excessive knee flexion at initial contact with a transtibial prosthesis is caused by: excessive dorsiflexion of the prosthetic foot (or insufficient plantarflexion), which shifts the ground reaction force posterior to the knee joint axis, or excessive socket flexion that promotes a knee-flexed posture. Both cause the knee to buckle at heel strike. Excessive plantarflexion would cause the opposite problem (knee hyperextension or knee extension moment at initial contact). Strong hip extensors would help control, not cause, knee flexion. A limb that is too long causes vaulting on the sound side. The prosthetist adjusts alignment to correct this gait deviation.", difficulty: 3, category: "Prosthetics & Orthotics", topic: "Transtibial Prosthetic Gait Alignment" },
  { id: "pta-b26-038", stem: "A patient with a recent spinal cord injury at C5 is in an acute rehabilitation setting. The MOST important functional goal for discharge is:", options: ["Independent power wheelchair mobility, ability to direct own care, and setup assistance for feeding with adaptive equipment", "Independent ambulation on all surfaces", "Return to full employment immediately", "Independent driving of a standard vehicle"], correctIndex: 0, rationale: "C5 SCI preserves deltoid and biceps function but lacks wrist extensors (C6), triceps (C7), and hand function (C8-T1). Realistic functional goals: independent power wheelchair mobility (joystick control), ability to direct caregivers in daily care routine (essential for safety and autonomy), and feeding with adaptive equipment after setup (universal cuff, built-up utensils). Independent ambulation is not realistic. Full employment may be possible long-term with accommodations but not as an immediate discharge goal. Standard vehicle driving is not possible; modified van with adaptive controls is a long-term goal. Setting realistic, achievable goals based on neurological level is critical for patient motivation and discharge planning.", difficulty: 2, category: "Neurological Rehabilitation", topic: "C5 SCI Discharge Goals" },
  { id: "pta-b26-039", stem: "A PTA is measuring circumferential measurements of bilateral upper extremities to monitor lymphedema. Measurements are taken at 4 cm intervals starting from the ulnar styloid process. This measurement technique is called:", options: ["Circumferential tape measurement method, which is used to calculate limb volume and monitor lymphedema progression or response to treatment over time", "Manual muscle testing", "Goniometric measurement", "Functional capacity evaluation"], correctIndex: 0, rationale: "Circumferential tape measurement at standardized intervals (typically every 4 cm from a bony landmark) is the clinical standard for lymphedema monitoring. Serial measurements at consistent landmarks allow: calculation of limb volume using the truncated cone formula, comparison between affected and unaffected limbs (>2 cm difference at any level suggests lymphedema), and tracking treatment response over time. The technique must use consistent landmarks, consistent tape tension, and consistent measurement intervals. Manual muscle testing assesses strength. Goniometry measures joint ROM. Functional capacity evaluation assesses work-related physical abilities. Water displacement volumetry is the gold standard but less practical clinically.", difficulty: 1, category: "Data Collection & Measurement", topic: "Lymphedema Circumference Measurement" },
  { id: "pta-b26-040", stem: "A PTA is treating a patient with chronic obstructive pulmonary disease who uses a rollator walker. During ambulation training, the patient becomes dyspneic. The MOST appropriate immediate response is:", options: ["Have the patient stop, lean forward on the rollator with arms supported (tripod position), and perform pursed-lip breathing until dyspnea subsides", "Encourage the patient to walk faster to finish the distance", "Have the patient lie supine on the floor", "Remove the rollator and have the patient walk without support"], correctIndex: 0, rationale: "The tripod position (leaning forward on the rollator with arms supported) is a recovery position for COPD-related dyspnea. It optimizes respiratory mechanics by: fixing the shoulder girdle (allowing accessory muscles of respiration to assist ventilation), positioning the diaphragm optimally, and reducing venous return (decreasing cardiac preload). Pursed-lip breathing creates back pressure to prevent airway collapse and improves gas exchange. Walking faster increases oxygen demand and worsens dyspnea. Supine position increases venous return and may worsen breathlessness. Removing the walker removes the upper extremity fixation needed for accessory muscle use. The rollator specifically allows this recovery position, which is an advantage over standard walkers.", difficulty: 1, category: "Cardiopulmonary Physical Therapy", topic: "COPD Dyspnea Recovery Position" },
  { id: "pta-b26-041", stem: "A PTA is performing wound measurements on a stage IV pressure injury on the sacrum. The wound measures 8 cm length x 5 cm width x 2 cm depth, with 1.5 cm of undermining at the 3 o'clock position. The PTA should document:", options: ["All measurements including length, width, depth, and undermining location and extent using the clock face method, with the patient's head at 12 o'clock", "Only that the wound is 'large'", "Length and width only, ignoring depth and undermining", "An estimate of the wound size without measuring"], correctIndex: 0, rationale: "Comprehensive wound documentation includes: length (longest measurement head-to-toe), width (longest measurement perpendicular to length), depth (deepest point measured with a cotton-tip applicator), and undermining/tunneling described using the clock face method (12 o'clock = toward the head, 6 o'clock = toward the feet, 3 o'clock = patient's left, 9 o'clock = patient's right). This specific documentation: 8 x 5 x 2 cm with 1.5 cm undermining at 3 o'clock. Vague descriptions ('large') are clinically useless. Omitting depth and undermining misses critical information about tissue destruction extent. Estimates without measurement prevent accurate tracking of healing progress. Consistent measurement techniques allow reliable tracking.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Wound Measurement Documentation" },
  { id: "pta-b26-042", stem: "A PTA is educating a patient about the proper technique for a seated hamstring stretch. The patient should:", options: ["Sit on the edge of a chair with one leg extended, heel on floor, toes up, and gently lean forward at the hips while maintaining a neutral spine until a stretch is felt in the posterior thigh, holding for 30 seconds", "Bounce rapidly at the end range of the stretch", "Round the spine forward to maximize the stretch sensation", "Hold the stretch for 5 seconds and repeat 1 time"], correctIndex: 0, rationale: "Proper static hamstring stretching technique: one leg extended with heel on floor (lengthens hamstring), lean forward from the hips (not the spine) maintaining a neutral spine (isolates hamstring stretch from lumbar flexion), hold for 30 seconds (minimum effective duration for plastic deformation of muscle-tendon unit), and repeat 3-4 times. Ballistic bouncing activates the stretch reflex (muscle spindle activation causes protective contraction), reducing stretch effectiveness and risking muscle injury. Rounding the spine creates the stretch sensation in the lumbar spine rather than the hamstrings. Five-second holds are insufficient for tissue elongation. Evidence supports 30-60 second holds, 3-4 repetitions, performed daily for flexibility gains.", difficulty: 1, category: "Therapeutic Exercise", topic: "Hamstring Stretching Technique" },
  { id: "pta-b26-043", stem: "A PTA is assisting with the management of a patient in the ICU who has bilateral lower extremity sequential compression devices (SCDs). The PRIMARY purpose of these devices is:", options: ["To prevent deep vein thrombosis by providing intermittent pneumatic compression that mimics the calf muscle pump to maintain venous blood flow", "To strengthen the calf muscles", "To reduce arterial blood flow to the legs", "To increase swelling in the lower extremities"], correctIndex: 0, rationale: "Sequential compression devices (SCDs) provide intermittent pneumatic compression that mimics the calf muscle pump mechanism to maintain venous blood flow velocity in immobilized patients. This prevents blood stasis (one of Virchow's triad: stasis, endothelial injury, hypercoagulability) and reduces DVT risk by 50-60%. SCDs do not strengthen muscles (passive compression). They enhance venous, not reduce arterial, flow. They reduce, not increase, lower extremity edema. Contraindications include: existing DVT (risk of embolization), peripheral vascular disease (may compromise arterial perfusion), skin infections, and open wounds on the legs. The PTA should ensure proper fit and continuous use when the patient is in bed.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "SCD DVT Prevention" },
  { id: "pta-b26-044", stem: "During gait analysis, a PTA observes that a patient with a left transfemoral prosthesis demonstrates abducted gait (wide-based, circumducting the prosthetic limb). The MOST likely cause is:", options: ["The prosthetic limb is too long, the socket is too tight distally, or the patient has developed a habit of abduction to clear the limb during swing phase", "The prosthetic limb is too short", "The patient's hip adductors are too strong", "The prosthetic knee joint is functioning perfectly"], correctIndex: 0, rationale: "Abducted gait (circumduction) with a transfemoral prosthesis is caused by: excessive prosthetic length (patient abducts to clear the floor during swing), distal socket tightness (pushes the limb laterally), inadequate knee flexion during swing (limb does not shorten sufficiently for clearance), or habitual abduction pattern. A short prosthesis would not require abduction for clearance. Strong hip adductors would resist, not cause, abduction. The prosthetic knee may need adjustment for adequate swing-phase flexion. The prosthetist should check alignment, length, and socket fit. Gait training with the PTA focuses on breaking the abduction habit once prosthetic factors are corrected.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "Transfemoral Abducted Gait" },
  { id: "pta-b26-045", stem: "A PTA is developing a progressive balance training program for a patient recovering from a vestibular disorder. The correct progression sequence is:", options: ["Static stance on firm surface → static on foam → dynamic activities on firm → dynamic on foam → tandem stance → single-leg stance → eyes closed variations at each level", "Start with single-leg stance on a BOSU ball with eyes closed", "Only perform seated balance activities", "Progress directly to sport-specific agility drills"], correctIndex: 0, rationale: "Balance training progression follows systematic challenge increases across multiple dimensions: surface stability (firm → compliant/foam → unstable), stance width (bilateral → tandem → single-leg), visual input (eyes open → eyes closed), static → dynamic tasks, and simple → complex/dual-task conditions. Starting on single-leg BOSU with eyes closed is too advanced and unsafe. Seated-only activities do not challenge standing balance systems. Sport-specific drills require a foundation of basic balance competency. Each level should be mastered before progression. Vestibular rehabilitation specifically challenges the vestibular system by manipulating visual and somatosensory inputs to force vestibular reliance.", difficulty: 2, category: "Gait Training & Assistive Devices", topic: "Vestibular Balance Progression" },
  { id: "pta-b26-046", stem: "A PTA is performing a standardized outcome measure using the Activities-Specific Balance Confidence (ABC) Scale. This tool measures:", options: ["The patient's self-reported confidence in maintaining balance during 16 specific activities, expressed as a percentage from 0% (no confidence) to 100% (complete confidence)", "Objective balance ability measured by the therapist", "Muscle strength of the lower extremities", "Cognitive function and memory"], correctIndex: 0, rationale: "The ABC Scale is a 16-item self-report questionnaire measuring balance confidence during specific activities (reaching on tiptoes, walking on icy sidewalks, stair climbing, etc.). Scores range from 0% (no confidence) to 100% (complete confidence). Average score interpretation: >80% = high physical functioning, 50-80% = moderate physical functioning, <50% = low physical functioning with high fall risk. The ABC measures perceived confidence, not objective balance ability (Berg Balance Scale measures that). It does not measure strength or cognition. The ABC is valuable because balance confidence independently predicts falls; low confidence leads to activity restriction, deconditioning, and increased fall risk (fear-avoidance cycle).", difficulty: 1, category: "Data Collection & Measurement", topic: "ABC Scale Balance Confidence" },
  { id: "pta-b26-047", stem: "A PTA is using neuromuscular electrical stimulation (NMES) to facilitate quadriceps contraction in a patient 3 days post-TKA. The electrodes should be placed:", options: ["Over the motor points of the vastus medialis and vastus lateralis muscles, with intensity increased until a visible, palpable contraction is achieved", "Over the patellar tendon and tibial tuberosity", "Over the hamstring muscles on the posterior thigh", "On the contralateral (non-surgical) leg"], correctIndex: 0, rationale: "NMES for quadriceps facilitation post-TKA: electrodes placed over the motor points of the VMO and VL provide the most effective quadriceps contraction. The motor point is the location where the motor nerve enters the muscle belly, requiring the least current to produce contraction. Intensity is increased until a visible, palpable contraction is achieved (subthreshold stimulation provides no strengthening benefit). Patellar tendon and tibial tuberosity are bony landmarks, not muscle tissue. Stimulating the hamstrings would not facilitate quadriceps function. Contralateral leg stimulation provides no benefit to the surgical leg. Early NMES after TKA helps overcome arthrogenic muscle inhibition (AMI), which is reflexive quadriceps shutdown due to joint effusion.", difficulty: 2, category: "Therapeutic Modalities", topic: "NMES Quadriceps Post-TKA" },
  { id: "pta-b26-048", stem: "A PTA is treating a 78-year-old patient with osteoporosis and a history of two vertebral compression fractures. The patient asks about returning to her yoga class. The PTA should advise:", options: ["Modified yoga is possible but must avoid all forward flexion (forward folds), heavy spinal loading, and inverted poses; extension-based and weight-bearing poses are preferred", "All yoga poses are safe for osteoporotic patients", "Yoga is completely contraindicated for patients with osteoporosis", "Only hot yoga is safe for osteoporosis patients"], correctIndex: 0, rationale: "Yoga with osteoporosis requires significant modification: avoid forward flexion poses (forward folds, plough pose) which increase anterior vertebral compression fracture risk, avoid heavy spinal loading and inverted poses that increase fall and fracture risk. Extension-based poses (cobra, sphinx) unload the anterior vertebral body. Weight-bearing poses (warrior, tree) provide beneficial mechanical loading for bone density. Blanket permission for all yoga ignores the real fracture risk. Complete prohibition of yoga unnecessarily restricts beneficial physical activity. Hot yoga does not specifically address osteoporosis concerns and the heat may cause orthostatic hypotension risk. The PTA should communicate specific pose modifications to the yoga instructor.", difficulty: 2, category: "Patient Education & Home Programs", topic: "Osteoporosis Yoga Modification" },
  { id: "pta-b26-049", stem: "A PTA is performing manual percussion (cupping) as part of chest physiotherapy. The technique should be performed:", options: ["With cupped hands alternating rhythmically over the affected lung segment for 3-5 minutes, with the patient in the appropriate postural drainage position, avoiding percussion over the spine, sternum, and kidneys", "With flat hands slapping the chest as hard as possible", "Only over the spine and sternum for maximum effect", "For 30 seconds regardless of secretion status"], correctIndex: 0, rationale: "Manual percussion technique: hands cupped (creating an air pocket that transmits energy waves through the chest wall to loosen secretions), alternating rhythmic clapping over the specific lung segment being drained, performed during postural drainage positioning for 3-5 minutes per segment. Avoid percussion over: spine (bony prominence), sternum (bony prominence), kidneys (organ damage risk), breast tissue, and surgical incisions. Flat-hand slapping causes pain and tissue damage without the therapeutic air-cushion effect. Spine and sternum percussion causes pain and potential injury. Thirty seconds is insufficient for adequate secretion mobilization. Contraindications include: rib fractures, hemoptysis, pulmonary embolism, and unstable cardiovascular status.", difficulty: 1, category: "Cardiopulmonary Physical Therapy", topic: "Chest Percussion Technique" },
  { id: "pta-b26-050", stem: "A PTA is providing discharge education to a patient after total hip arthroplasty (anterior approach). The precautions for this surgical approach differ from posterior approach in that:", options: ["Anterior approach precautions restrict hip extension, external rotation, and combined extension with adduction, rather than the flexion/adduction/IR restrictions of the posterior approach", "Anterior and posterior approaches have identical precautions", "Anterior approach has no movement precautions", "Anterior approach restricts only hip flexion beyond 90°"], correctIndex: 0, rationale: "Anterior approach THA precautions are OPPOSITE to posterior approach because different structures are disrupted. Anterior approach dissects between muscles (tensor fascia lata and sartorius/rectus femoris) and disrupts the anterior capsule. Precautions: avoid hip extension beyond neutral, avoid external rotation, and avoid combined extension with adduction (positions that stress the anterior capsule). Posterior approach disrupts short external rotators and posterior capsule: avoid flexion >90°, adduction past midline, and internal rotation. The approaches have fundamentally different precautions. Anterior approach does have precautions despite some marketing claims. Anterior approach does not restrict flexion >90° (this is a posterior precaution). The PTA must know the surgical approach to provide correct patient education.", difficulty: 3, category: "Musculoskeletal Rehabilitation", topic: "Anterior THA Precautions" },
  { id: "pta-b26-051", stem: "A PTA is treating a geriatric patient who demonstrates a shuffling gait pattern, forward-flexed posture, and difficulty with transitions from sit-to-stand. The patient is NOT diagnosed with Parkinson's disease. These findings in an elderly patient without PD may indicate:", options: ["Normal pressure hydrocephalus, which presents with the classic triad of gait disturbance, urinary incontinence, and cognitive decline, and warrants referral to the physician", "Normal aging that requires no further evaluation", "Only weakness requiring strengthening exercises", "A condition that physical therapy cannot address"], correctIndex: 0, rationale: "Normal pressure hydrocephalus (NPH) presents with the classic Hakim triad: gait disturbance (magnetic/shuffling gait), urinary incontinence, and cognitive decline (dementia). These symptoms can mimic Parkinson's disease but occur without the resting tremor and cogwheel rigidity of PD. NPH is potentially treatable with CSF shunting, making recognition and physician referral critical. While shuffling gait can occur with normal aging, the combination of gait disturbance, incontinence, and cognitive decline in an elderly patient should raise suspicion for NPH. The PTA should document the findings and communicate them to the supervising PT for physician referral. NPH is one of the reversible causes of dementia.", difficulty: 3, category: "Geriatric Rehabilitation", topic: "Normal Pressure Hydrocephalus Recognition" },
  { id: "pta-b26-052", stem: "A PTA is using the Functional Reach Test (FRT) to assess a patient's balance. The patient reaches 6 inches forward without stepping or losing balance. This result indicates:", options: ["Increased fall risk, as scores less than 7 inches on the Functional Reach Test are associated with a 2x increased risk of falls in older adults", "Excellent balance with no fall risk", "The test is not a valid measure of fall risk", "Normal functional reach for all age groups"], correctIndex: 0, rationale: "The Functional Reach Test measures the maximum distance a person can reach forward beyond arm's length while maintaining a fixed base of support. Normative data: scores <7 inches indicate 2x fall risk, scores <6 inches indicate 4x fall risk in older adults. Normal functional reach for adults is 10-13 inches, decreasing with age. This patient's 6-inch reach falls below the 7-inch cutoff, indicating clinically significant fall risk requiring intervention. The FRT is a valid, reliable, and quick screening tool for fall risk. It is not normal for all age groups. The PTA should implement balance training, review fall prevention strategies, and consider assistive device assessment.", difficulty: 1, category: "Data Collection & Measurement", topic: "Functional Reach Test Interpretation" },
  { id: "pta-b26-053", stem: "A PTA is teaching a patient proper body mechanics for lifting. The MOST important instruction is:", options: ["Keep the load close to the body, bend at the hips and knees (not the spine), engage core muscles before lifting, and avoid twisting while carrying the load", "Bend at the waist with straight legs to reach the object", "Hold the load as far from the body as possible for better leverage", "Twist the spine to place the object to the side"], correctIndex: 0, rationale: "Evidence-based lifting mechanics: keeping the load close reduces the moment arm, decreasing spinal forces by up to 50%. Hip/knee bending (squat lift) uses the powerful lower extremity muscles rather than the smaller spinal extensors. Core engagement (abdominal bracing) increases intra-abdominal pressure, providing spinal support. Avoiding twisting prevents combined flexion-rotation loading (the most dangerous spinal loading pattern for disc herniation). Bending at the waist with straight legs (stoop lift) maximizes spinal loading. A far load increases the moment arm and spinal force exponentially. Spinal twisting under load creates asymmetric disc loading and is a primary mechanism for disc injury.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Proper Lifting Body Mechanics" },
  { id: "pta-b26-054", stem: "A PTA is treating a patient post-stroke who demonstrates learned non-use of the affected upper extremity. The patient uses only the unaffected arm for all activities despite having some voluntary movement in the affected arm. This phenomenon is caused by:", options: ["A vicious cycle where initial motor difficulty leads to compensatory use of the unaffected arm, which is negatively reinforced by success, causing progressive cortical reorganization away from the affected limb", "Physical destruction of all motor pathways to the affected arm", "Patient laziness and poor motivation", "Normal recovery pattern that should not be addressed"], correctIndex: 0, rationale: "Learned non-use develops through a behavioral conditioning cycle: initial motor difficulty after stroke → compensatory use of unaffected arm for functional tasks → successful completion with unaffected arm provides negative reinforcement → reduced attempts with affected arm → cortical reorganization (use-dependent plasticity) reduces affected arm representation → further difficulty using affected arm. This is NOT caused by complete motor pathway destruction (some voluntary movement exists). It is NOT laziness; it is a neuroplastic maladaptation. It should be actively addressed through constraint-induced movement therapy (CIMT), forced-use strategies, and bilateral training. Neuroplasticity is bidirectional: non-use drives further loss, while forced use can reverse cortical reorganization.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Stroke Learned Non-Use" },
  { id: "pta-b26-055", stem: "A PTA is performing pulmonary rehabilitation for a patient with idiopathic pulmonary fibrosis. The exercise prescription should:", options: ["Include moderate-intensity aerobic training with supplemental oxygen titrated to maintain SpO2 >88-90%, interval training format, and close monitoring for exercise-induced desaturation", "Avoid all exercise as it may worsen fibrosis", "Include maximum-intensity continuous exercise without oxygen supplementation", "Focus exclusively on upper body strengthening with no aerobic component"], correctIndex: 0, rationale: "Pulmonary fibrosis (restrictive lung disease) reduces gas exchange surface area. Exercise induces significant desaturation due to increased oxygen demand. Evidence supports: moderate-intensity aerobic training (improves functional capacity and quality of life), supplemental oxygen titrated to maintain SpO2 >88-90% during exercise, interval training (shorter exercise bouts with rest allow recovery from desaturation), and close monitoring of SpO2 throughout exercise. Exercise does not worsen fibrosis and is beneficial. Maximum intensity without oxygen risks dangerous hypoxemia. Upper body strengthening alone misses the cardiovascular benefit of aerobic training. The PTA must have supplemental oxygen available and be prepared to adjust exercise intensity based on real-time SpO2 monitoring.", difficulty: 3, category: "Cardiopulmonary Physical Therapy", topic: "Pulmonary Fibrosis Exercise" }
];
